CREATE OR REPLACE VIEW vw_job_boards WITH (security_invoker = ON) AS
SELECT
  t.job_board_id,
  t.name,
  t.description,
  t.is_enabled,
  t.max_pages,
  t.is_headless,
  t.browser_channel,
  calc_job_boards_job_listings(t.job_board_id) AS job_listings
FROM job_boards t;

CREATE OR REPLACE VIEW vw_search_urls WITH (security_invoker = ON) AS
SELECT
