CREATE OR REPLACE VIEW vw_job_listings WITH (security_invoker = ON) AS
SELECT
  t.job_listing_id,
  t.name,
  t.job_board,
  t.external_id,
  t.company,
  t.location,
  t.url,
  t.full_text,
  t.posted_at,
  t.comp_min,
  t.comp_max,
